mapper.select:
SELECT p.PLC_NO AS plcNo, p.PLC_NAME AS plcName, p.PLC_ADDR AS plcAddr, p.PLC_AVG_RATING AS plcAvgRating FROM PLACE p LEFT JOIN PLACE_FOOD f ON p.PLC_NO = f.FOOD_PLC_NO WHERE p.PLC_CAT_CD = 'PLC003' AND p.PLC_USE_YN = 'Y'
AND p.PLC_RGN_CD = #{rgnCd}
ORDER BY p.PLC_NO DESC LIMIT #{offset}, #{size}

SELECT p.PLC_NO AS plcNo, p.PLC_ID AS plcId, p.PLC_RGN_CD AS plcRgnCd, p.PLC_NAME AS plcName, p.PLC_ADDR AS plcAddr, p.PLC_LAT AS plcLat, p.PLC_LOT AS plcLot, p.PLC_TELNO AS plcTelno, p.PLC_OVERVIEW AS plcOverview, p.PLC_MAIN_IMG_URL AS plcMainImgUrl, p.PLC_THUM_IMG_URL AS plcThumImgUrl, p.PLC_FLT_CD AS plcFltCd, p.PLC_AVG_RATING AS plcAvgRating, p.PLC_REVIEW_CNT AS plcReviewCnt, f.FOOD_OPENING_HOURS AS foodOpeningHours, f.FOOD_PARKING AS foodParking, f.FOOD_RESTDATE AS foodRestdate, f.FOOD_MENU AS foodMenu, f.FOOD_INFOCENTER AS foodInfocenter FROM PLACE p LEFT JOIN PLACE_FOOD f ON p.PLC_NO = f.FOOD_PLC_NO WHERE p.PLC_CAT_CD = 'PLC003'
AND p.PLC_RGN_CD = #{rgnCd}
ORDER BY p.PLC_NO DESC
